module top_module(
    input [3:0] X_A,
    input [3:0] B,
    input SUB,
    output reg [3:0] SUM,
    output reg CARRY
);always @(*) begin
        if (SUB) begin
            SUM <= X_A - B;
            CARRY <= (X_A < B);
        end else begin
            SUM <= X_A + B;
            CARRY <= (SUM < X_A);
        end
    end

endmodule
